SELECT state_abbr, population, 
       ROW_NUMBER() OVER (ORDER BY population DESC) AS population_rank
FROM states;

SELECT state_id, AVG(age_adjusted_prevalence) AS average_age_adjusted_prevalence
FROM prevalences
GROUP BY state_id;

SELECT COUNT(*)
FROM prevalences
WHERE condition_id = 123 AND year = 2022;

SELECT COUNT(*) 
FROM prevalences 
WHERE condition_id NOT IN (SELECT condition_id FROM health_conditions);

SELECT p.quartile, ci.interval_description
FROM prevalences p
JOIN confidence_intervals ci ON p.confidence_interval = ci.interval_id;

SELECT 
    (SELECT COUNT(DISTINCT user_id) FROM users) AS total_users, 
    (SELECT COUNT(DISTINCT report_id) FROM reports) AS total_reports;
